    public static void run(final long expectRunSeconds) {
        final Benchmark benchmark = new Benchmark();
        long lng = 0L;
        long lng2 = 0L;
        while (lng < expectRunSeconds) {
            if (benchmark.duration() / 1000L != lng2) {
                final long n = lng;
                lng2 = benchmark.duration() / 1000L;
                lng = n + 1L;
                Debug.i("actualRunSeconds = " + lng + ", runTotalDuration = " + lng2);
            }
        }
    }
    
