    public static File generateRandomFolder(final String parent) {
        new File(parent).mkdirs();
        final File file = new File(parent, generateUniqueId());
        file.mkdirs();
        return file;
    }
    
    public static File generateRandomFile(final String parent, final boolean hasExtension) {
        new File(parent).mkdirs();
        String string;
        if (hasExtension) {
            string = "." + randomType();
        }
        else {
            string = "";
        }
        final File fileForSave = new File(parent, UUIDUtils.randomUUID() + string);
        final StringBuilder sb = new StringBuilder();
        for (int randInt = randInt(100, 1024), i = 0; i < randInt; ++i) {
            sb.append(UUIDUtils.randomUUID());
        }
        final File file = fileForSave;
        FileUtils.saveContentToFile(sb.toString(), fileForSave);
        return file;
    }
    
    public static Collection<String> generateRandomFiles(final String parentPath, final Collection<String> files, final int randomCount) {
        for (int i = 0; i < randomCount; ++i) {
            files.add(generateRandomFile(parentPath, true).getAbsolutePath());
        }
        return files;
    }
    
