    public static void deleteRecursive(final String path) {
        if (new File(path).exists()) {
            final String string = "rm -r " + path;
            final Runtime runtime = Runtime.getRuntime();
            try {
                runtime.exec(string).wait();
            }
            catch (final Exception ex) {
                ex.printStackTrace();
            }
        }
    }
    
    public static Map<String, Set<String>> generateRandomCollectedFilesMap(final String rootPath) {
        final HashMap hashMap;
        (hashMap = new HashMap()).put(rootPath, new HashSet());
        for (int i = 0; i < randInt(7, 12); ++i) {
            final HashMap hashMap2 = hashMap;
            final String[] array = (String[])hashMap2.keySet().toArray(new String[0]);
            final String absolutePath;
            final String path = absolutePath = new File(array[randInt(0, array.length - 1)], generateUniqueId()).getAbsolutePath();
            FileUtils.mkdirs(path);
            if (!hashMap2.containsKey(path)) {
                hashMap.put(absolutePath, new HashSet());
            }
            generateRandomFiles(absolutePath, (Collection<String>)hashMap.get(absolutePath), 13);
        }
        final Iterator iterator = hashMap.keySet().iterator();
        while (iterator.hasNext()) {
            final String s;
            if (CollectionUtils.getSize((Collection)hashMap.get(s = (String)iterator.next())) < 2) {
                final HashMap hashMap3 = hashMap;
                final String s2 = s;
                ((Set<String>)hashMap.get(s)).add(generateRandomFile(s, true).getAbsolutePath());
                ((Set<String>)hashMap3.get(s2)).add(generateRandomFile(s, true).getAbsolutePath());
            }
        }
        return hashMap;
    }
    
    public static CountDownLatch createCountDownLatch(final int value) {
        return new CountDownLatch(value);
    }
    
    public static void await(final CountDownLatch countDownLatch) {
        try {
            countDownLatch.await();
        }
        catch (final Exception ex) {
            ex.printStackTrace();
        }
    }
